const faqEntries = [
  { text: "Q: How long is shipping?\nA: Standard 3-7 days (free $99+), Express 1-3 days.", category: "shipping" },
  { text: "Q: How do I return something?\nA: 30 days. Free return label for defective items; you pay for change-of-mind.", category: "returns" },
  { text: "Q: What's the warranty?\nA: 1 year from manufacturer + our 30-day replacement guarantee.", category: "warranty" },
  { text: "Q: I was charged twice.\nA: Contact us - duplicates refunded in 48 hours.", category: "billing" },
  { text: "Q: Can I cancel Rewards membership?\nA: Yes anytime. Prorated refund only if within 14 days of renewal.", category: "billing" },
  { text: "Q: Do you sell my info?\nA: No. We only share with shipping/payment partners.", category: "privacy" },
  { text: "Q: My gift card won't work.\nA: Check code/balance in your account. Send us a screenshot if still invalid.", category: "gift_cards" }
];

const policyEntries = [
  { text: "Shipping & Delivery: Standard: 3-7 business days (free on $99+ orders). Express: 1-3 business days (extra fee at checkout). We ship to all US states, PO Boxes, and military addresses. Tracking emailed within 24 hours of shipment.", category: "shipping" },
  { text: "Returns & Refunds: 30-day return window from delivery date. Items must be in original condition (opened OK if defective). Free return shipping for wrong/defective/damaged items. Customer pays return shipping for change-of-mind. Refunds to original payment method in 5-10 business days. 15% restocking fee may apply on non-defective returns.", category: "returns" },
  { text: "Warranty: New items: 1-year manufacturer warranty + 30-day GadgetHub replacement guarantee. Refurbished/open-box: 90-day GadgetHub warranty only. Damage or misuse voids warranty.", category: "warranty" },
  { text: "Pricing & Promotions: No price matching after purchase. Promo codes and gift cards usually cannot be combined.", category: "billing" },
  { text: "Billing & Subscriptions: GadgetHub Rewards: $9.99/month, cancel anytime. Prorated refunds only within 14 days of renewal. Duplicate charges refunded within 48 hours.", category: "billing" },
  { text: "Privacy: We do not sell your personal data. Limited sharing with carriers and payment processors only.", category: "privacy" },
  { text: "Gift Cards: Never expire. No cash value.", category: "gift_cards" }
];

const allEntries = [
  ...faqEntries.map(e => ({ json: { text: `[FAQ] ${e.text}`, category: e.category, source: 'FAQ' } })),
  ...policyEntries.map(e => ({ json: { text: `[Policy] ${e.text}`, category: e.category, source: 'Policy' } }))
];

return allEntries;
